+        // NonDeductibleVATAmtPerUnit is in purchase currency, NonDeductibleVATAmtPerUnitLCY is in LCY
+        // We need to convert them to job currency
+        
+        // If job currency is empty (use LCY), use LCY amount
+        if JobJnlLine."Currency Code" = '' then
+            exit; // Use LCY amounts as-is
+        
+        // If job currency equals purchase currency, use purchase currency amounts as-is
+        if JobJnlLine."Currency Code" = PurchLine."Currency Code" then
+            exit; // Use amounts as-is
+        
+        // Job currency is different from both LCY and purchase currency
+        // Convert to job currency
+        if PurchLine."Currency Code" <> '' then
+            PurchCurrency.Get(PurchLine."Currency Code");
+        
+        if PurchLine."Currency Code" = '' then begin
+            // Purchase line is in LCY, convert from LCY to job currency
+            NonDeductibleVATAmtPerUnit := 
