+        // If job currency is empty (use LCY)
+        if JobJnlLine."Currency Code" = '' then begin
+            // Job uses LCY, need to convert NonDeductibleVATAmount to LCY if journal is in foreign currency
+            if GenJnlLine."Currency Code" <> '' then begin
+                // Journal line is in a foreign currency, convert from foreign currency to LCY
+                GenJnlCurrFactor := GenJnlLine."Currency Factor";
