+                        GenJnlLine."Posting Date",
+                        GenJnlLine."Currency Code",
+                        NonDeductibleVATAmount,
+                        GenJnlCurrFactor), LCYCurrency."Amount Rounding Precision");
+                
+                // Convert from LCY to job currency
+                NonDeductibleVATAmount := 
+                    Round(
+                        CurrencyExchRate.ExchangeAmtLCYToFCY(
+                            GenJnlLine."Posting Date",
+                            JobJnlLine."Currency Code",
+                            AmountInLCY,
